import { Subject, Observable } from 'rxjs';
import { wsStatusMsg, wsConnectionStatusEvent, wsServiceReceiveDataMsg, wsServiceConnectDef, reconnectIntervalInMilli } from './nikkiDef';

export class wsHandlerImpl {
    private wsDataMsgSubject: Subject<any> = new Subject();
    private connectionStatSubject: Subject<wsStatusMsg> = new Subject();
    private wsHandl: WebSocket | undefined = undefined;
    private serverUrl: string = '';
    private reconnectInterval: number = reconnectIntervalInMilli;
    private shouldReconnect: boolean = true;
    private reconnectTimeout: any = undefined;

    constructor() {
        this.wsHandl = undefined;
        this.shouldReconnect = true;
        this.reconnectTimeout = null;
    }

    

    getConnectionStatus(): boolean {
        let status = false;
        try {
            if (this.wsHandl) {
                status = (this.wsHandl.readyState === WebSocket.OPEN);
            }
        } catch (e: any) {
            console.error('Exception while getConnectionStatus:', e.message);
        }
        return status;
    }

    getWsStatusSubject(): Observable<wsStatusMsg> {
        return this.connectionStatSubject;
    }

    getWsDataSubject(): Observable<any> {
        return this.wsDataMsgSubject;
    }

    private onWsMessage(msg: MessageEvent): void {
        try {
            if (msg && msg.data) {
                const jevent = JSON.parse(msg.data);
                this.wsDataMsgSubject.next(jevent);
            }
        } catch (e: any) {
            console.error('Exception while onWsMessage:', e.message);
        }
    }

    private wsOnConnect(): void {
        try {
            console.info('Playground connected.');
            const wstat = new wsStatusMsg();
            wstat.type = wsConnectionStatusEvent.Connected;
            this.connectionStatSubject.next(wstat);
        } catch (e: any) {
            console.error('Exception while wsOnConnect:', e.message);
        }
    }

    private wsOnError(err: Event): void {
        try {
            console.info('Playground error:', err);
            const wstat = new wsStatusMsg();
            wstat.type = wsConnectionStatusEvent.Error;
            wstat.data = err;
            this.connectionStatSubject.next(wstat);
        } catch (e: any) {
            console.error('Exception while wsOnError:', e.message);
        }
    }

    private wsOnClose(): void {
        try {
            console.info('Playground closed.');
            const wstat = new wsStatusMsg();
            wstat.type = wsConnectionStatusEvent.DisConnected;
            this.connectionStatSubject.next(wstat);
        } catch (e: any) {
            console.error('Exception while wsOnClose:', e.message);
        }
    }

    disconnect(): void {
        try {
            this.shouldReconnect = false;
            if (this.reconnectTimeout) {
                clearTimeout(this.reconnectTimeout);
                this.reconnectTimeout = null;
            }
            if (this.wsHandl && this.wsHandl.readyState === WebSocket.OPEN) {
                this.wsHandl.close(1000, 'Client initiated close');
            }
        } catch (e: any) {
            console.error('Exception while disconnect:', e.message);
        }
    }

    connect(wsConnectAddr: string): void {
        try {
            this.serverUrl = wsConnectAddr;
            if (this.wsHandl && this.wsHandl.readyState === WebSocket.OPEN) {
                return;
            }
            if (this.reconnectTimeout) {
                clearTimeout(this.reconnectTimeout);
                this.reconnectTimeout = null;
            }
            this.wsHandl = new WebSocket(this.serverUrl);
            this.wsHandl.onopen = () => this.wsOnConnect();
            this.wsHandl.onmessage = (event) => this.onWsMessage(event);
            this.wsHandl.onclose = () => {
                this.wsOnClose();
                if (this.shouldReconnect && this.wsHandl) {
                    this.reconnectTimeout = setTimeout(() => {
                        console.info('Trying to reconnect.');
                        const wstat = new wsStatusMsg();
                        wstat.type = wsConnectionStatusEvent.Reconnecting;
                        this.connectionStatSubject.next(wstat);
                        // this.wsHandl.connect(this.serverUrl);
                    }, this.reconnectInterval);
                }
            };
            this.wsHandl.onerror = (error) => this.wsOnError(error);
        } catch (e: any) {
            console.error('Exception while connect:', e.message);
        }
    }

    sendMessage(msg: any): void {
        try {
            if (this.wsHandl && this.wsHandl.readyState === WebSocket.OPEN) {
                this.wsHandl.send(JSON.stringify(msg));
            } else {
                console.error('Playground is not connected.');
                const wstat = new wsStatusMsg();
                wstat.type = wsConnectionStatusEvent.sendingDataWhileDisconnected;
                wstat.data = undefined;
                this.connectionStatSubject.next(wstat);
            }
        } catch (e: any) {
            console.error('Exception while sendMessage:', e.message);
        }
    }
}